1	/**
2	 * LayerInfinite MCP Server — tools/li-toggle-action.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * RUNTIME CIRCUIT BREAKER — Always registered, all modes.
5	 *
6	 * When an agent detects an action is consistently failing (e.g.,
7	 * a provider API is down), it can disable that action immediately.
8	 * Disabled actions are excluded from all LI recommendations and
9	 * resource injections. The action is NOT deleted — all historical
10	 * data is preserved. The developer can re-enable it from the
11	 * dashboard once the underlying issue is fixed.
12	 *
13	 * Maps to PUT /v1/admin/:action_id on the LI REST API.
14	 *
15	 * REST API contract (from admin/actions.ts toggleActionHandler):
16	 *   PUT /v1/admin/:id with body { is_active: boolean }
17	 *   Requires action_id (UUID).
18	 *
19	 * Auth: X-API-Key + adminAuthMiddleware (customer_admin role)
20	 * ══════════════════════════════════════════════════════════════
21	 */
22	
23	import { z } from 'zod';
24	import type { RestClient } from '../rest-client.js';
25	
26	export const LI_TOGGLE_ACTION_NAME = 'li_toggle_action';
27	
28	export const LI_TOGGLE_ACTION_DESCRIPTION =
29	  'Circuit breaker: temporarily disable a failing action or re-enable a fixed one. ' +
30	  'Disabled actions are immediately excluded from all LI recommendations and ' +
31	  'resource injections. The action and its historical data are preserved — ' +
32	  'the developer can re-enable it from the dashboard after fixing the issue.';
33	
34	export const liToggleActionSchema = {
35	  action_id: z.string().uuid().describe('UUID of the action to toggle (find via li_observe or dashboard)'),
36	  enabled: z.boolean().describe('false to circuit-break a failing action, true to re-enable'),
