67	          is_active: input.enabled,
68	          circuit_breaker: !input.enabled ? 'OPEN — action disabled' : 'CLOSED — action re-enabled',
69	          ...(input.reason ? { reason: input.reason } : {}),
70	          ...(result.data as object),
71	        }),
72	      }],
73	    };
74	  };
75	}
