1	#!/usr/bin/env node
2	
3	/**
4	 * LayerInfinite MCP Server — bin/cli.ts
5	 * ══════════════════════════════════════════════════════════════
6	 * Entry point for stdio transport. This is what Claude Desktop,
7	 * Cursor, Cline, and other MCP hosts spawn as a child process.
8	 *
9	 * Production hardening:
10	 *   - Graceful shutdown on SIGINT/SIGTERM
11	 *   - Unhandled rejection safety net
12	 *
13	 * Usage:
14	 *   LAYERINFINITE_API_KEY=xxx npx layerinfinite-mcp
15	 * ══════════════════════════════════════════════════════════════
16	 */
17	
18	import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
19	import { createServer } from '../src/index.js';
20	import { logger } from '../src/logger.js';
21	
22	async function main() {
23	  const server = createServer();
24	  const transport = new StdioServerTransport();
25	
26	  // ── Graceful shutdown ─────────────────────────────────────
27	  let isShuttingDown = false;
28	
29	  async function shutdown(signal: string) {
30	    if (isShuttingDown) return;
31	    isShuttingDown = true;
32	    logger.info('Shutting down', { signal });
33	
34	    try {
35	      await server.close();
36	      logger.info('Server closed cleanly');
37	    } catch (err) {
38	      logger.error('Error during shutdown', {
39	        error: err instanceof Error ? err.message : String(err),
40	      });
41	    }
42	
43	    process.exit(0);
44	  }
45	
46	  process.on('SIGINT', () => shutdown('SIGINT'));
47	  process.on('SIGTERM', () => shutdown('SIGTERM'));
48	
49	  // Safety net for unhandled rejections — log but don't crash
50	  process.on('unhandledRejection', (reason) => {
51	    logger.error('Unhandled rejection', {
52	      error: reason instanceof Error ? reason.message : String(reason),
53	      stack: reason instanceof Error ? reason.stack : undefined,
54	    });
55	  });
56	
57	  await server.connect(transport);
58	  logger.info('Connected via stdio transport');
59	}
60	
61	main().catch((err) => {
62	  logger.error('Fatal startup error', {
63	    error: err instanceof Error ? err.message : String(err),
64	    stack: err instanceof Error ? err.stack : undefined,
65	  });
66	  process.exit(1);
67	});
